{
  "name": "LibMaster Study Lab Manager",
  "description": "A comprehensive study lab management system with a visual 40-table grid, fee tracking, and student occupancy management."
}

export type PaymentMode = 'Cash' | 'Online';

export interface PaymentRecord {
  id: string;
  amount: number;
  date: string;
  mode: PaymentMode;
  forMonth: string; // Period covered
}

export interface Student {
  id: string;
  name: string;
  mobile: string;
  tableNumber: number;
  joiningDate: string;
  monthlyFee: number;
  lastPaidDate: string | null;
  nextDueDate: string;
  paymentHistory: PaymentRecord[];
}

export type ViewState = 'grid' | 'list' | 'analytics';

import { Student } from '../types';

const STORAGE_KEY = 'libmaster_students';

export const saveStudents = (students: Student[]): void => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(students));
};

export const getStudents = (): Student[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

import React from 'react';
import { Student } from '../types';
import { User, ShieldAlert, CheckCircle } from 'lucide-react';

interface TableGridProps {
  students: Student[];
  onTableClick: (tableNumber: number) => void;
}

const TableGrid: React.FC<TableGridProps> = ({ students, onTableClick }) => {
  const tables = Array.from({ length: 40 }, (_, i) => i + 1);

  const getStudentForTable = (tableNum: number) => {
    return students.find(s => s.tableNumber === tableNum);
  };

  const isOverdue = (nextDue: string) => {
    return new Date(nextDue) < new Date();
  };

  return (
    <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-8 gap-4 p-4">
      {tables.map(num => {
        const student = getStudentForTable(num);
        const overdue = student ? isOverdue(student.nextDueDate) : false;

        return (
          <button
            key={num}
            onClick={() => onTableClick(num)}
            className={`relative group h-28 rounded-xl border-2 transition-all duration-200 flex flex-col items-center justify-center p-2
              ${student 
                ? overdue 
                  ? 'border-rose-300 bg-rose-50 hover:bg-rose-100 shadow-sm' 
                  : 'border-emerald-300 bg-emerald-50 hover:bg-emerald-100 shadow-sm'
                : 'border-slate-200 bg-white hover:border-blue-400 hover:shadow-md'
              }`}
          >
            <span className="absolute top-1 left-2 text-xs font-bold text-slate-400">
              #{num}
            </span>

            {student ? (
              <>
                <User className={`w-8 h-8 ${overdue ? 'text-rose-500' : 'text-emerald-500'}`} />
                <span className="mt-1 text-sm font-semibold text-slate-700 truncate w-full text-center">
                  {student.name}
                </span>
                {overdue ? (
                  <div className="flex items-center gap-1 mt-1 text-[10px] font-bold text-rose-600 uppercase">
                    <ShieldAlert className="w-3 h-3" />
                    Overdue
                  </div>
                ) : (
                  <div className="flex items-center gap-1 mt-1 text-[10px] font-bold text-emerald-600 uppercase">
                    <CheckCircle className="w-3 h-3" />
                    Paid
                  </div>
                )}
              </>
            ) : (
              <>
                <div className="w-8 h-8 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center">
                  <span className="text-slate-300 font-bold">+</span>
                </div>
                <span className="mt-2 text-xs font-medium text-slate-400 uppercase tracking-wider">
                  Vacant
                </span>
              </>
            )}
          </button>
        );
      })}
    </div>
  );
};

export default TableGrid;

import React, { useState, useEffect } from 'react';
import { Student } from '../types';
import { X } from 'lucide-react';

interface StudentFormProps {
  student?: Student | null;
  tableNumber?: number;
  existingStudents: Student[];
  onSave: (student: Student) => void;
  onClose: () => void;
  onDelete?: (id: string) => void;
}

const StudentForm: React.FC<StudentFormProps> = ({ 
  student, 
  tableNumber, 
  existingStudents, 
  onSave, 
  onClose,
  onDelete 
}) => {
  const [formData, setFormData] = useState({
    name: '',
    mobile: '',
    tableNumber: tableNumber || 0,
    joiningDate: new Date().toISOString().split('T')[0],
    monthlyFee: 500,
  });

  const [error, setError] = useState('');

  useEffect(() => {
    if (student) {
      setFormData({
        name: student.name,
        mobile: student.mobile,
        tableNumber: student.tableNumber,
        joiningDate: student.joiningDate,
        monthlyFee: student.monthlyFee,
      });
    }
  }, [student]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Check duplicate table
    const duplicate = existingStudents.find(
      s => s.tableNumber === formData.tableNumber && s.id !== (student?.id || '')
    );
    if (duplicate) {
      setError(`Table ${formData.tableNumber} is already occupied by ${duplicate.name}`);
      return;
    }

    const nextDue = student ? student.nextDueDate : formData.joiningDate;

    const newStudent: Student = {
      id: student?.id || crypto.randomUUID(),
      name: formData.name,
      mobile: formData.mobile,
      tableNumber: formData.tableNumber,
      joiningDate: formData.joiningDate,
      monthlyFee: formData.monthlyFee,
      lastPaidDate: student?.lastPaidDate || null,
      nextDueDate: nextDue,
      paymentHistory: student?.paymentHistory || [],
    };

    onSave(newStudent);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
        <div className="flex items-center justify-between p-6 border-b">
          <h2 className="text-xl font-bold text-slate-800">
            {student ? 'Edit Student Details' : `Enroll for Table #${formData.tableNumber}`}
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {error && (
            <div className="p-3 bg-rose-50 border border-rose-200 text-rose-600 text-sm rounded-lg">
              {error}
            </div>
          )}

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
            <input
              required
              type="text"
              value={formData.name}
              onChange={e => setFormData({ ...formData, name: e.target.value })}
              className="w-full px-4 py-2 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="e.g. John Doe"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Mobile Number</label>
            <input
              required
              type="tel"
              value={formData.mobile}
              onChange={e => setFormData({ ...formData, mobile: e.target.value })}
              className="w-full px-4 py-2 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="e.g. 9876543210"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Table #</label>
              <input
                required
                type="number"
                min="1"
                max="40"
                value={formData.tableNumber}
                onChange={e => setFormData({ ...formData, tableNumber: parseInt(e.target.value) })}
                className="w-full px-4 py-2 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Joining Date</label>
              <input
                required
                type="date"
                value={formData.joiningDate}
                onChange={e => setFormData({ ...formData, joiningDate: e.target.value })}
                className="w-full px-4 py-2 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Monthly Fee (₹)</label>
            <input
              required
              type="number"
              value={formData.monthlyFee}
              onChange={e => setFormData({ ...formData, monthlyFee: parseInt(e.target.value) })}
              className="w-full px-4 py-2 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>

          <div className="pt-4 flex gap-3">
            <button
              type="submit"
              className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-semibold py-2.5 rounded-xl transition-colors shadow-lg shadow-blue-200"
            >
              {student ? 'Update Student' : 'Save Enrollment'}
            </button>
            {student && onDelete && (
              <button
                type="button"
                onClick={() => onDelete(student.id)}
                className="px-4 py-2.5 border border-rose-200 text-rose-600 hover:bg-rose-50 font-medium rounded-xl transition-colors"
              >
                Delete
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default StudentForm;

import React, { useState, useEffect, useMemo } from 'react';
import { Student, PaymentRecord, ViewState } from './types';
import { getStudents, saveStudents } from './services/storage';
import TableGrid from './components/TableGrid';
import StudentForm from './components/StudentForm';
import StudentDetails from './components/StudentDetails';
import { 
  Users, 
  LayoutGrid, 
  BarChart3, 
  Search, 
  Plus, 
  Library,
  Settings,
  Bell,
  Wallet
} from 'lucide-react';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [view, setView] = useState<ViewState>('grid');
  const [selectedTable, setSelectedTable] = useState<number | null>(null);
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setStudents(getStudents());
  }, []);

  // Save on change
  useEffect(() => {
    saveStudents(students);
  }, [students]);

  const stats = useMemo(() => {
    const total = students.length;
    const overdue = students.filter(s => new Date(s.nextDueDate) < new Date()).length;
    const monthlyRevenue = students.reduce((acc, curr) => acc + curr.monthlyFee, 0);
    return { total, overdue, monthlyRevenue };
  }, [students]);

  const filteredStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      s.mobile.includes(searchTerm) ||
      s.tableNumber.toString() === searchTerm
    );
  }, [students, searchTerm]);

  const handleTableClick = (tableNum: number) => {
    const student = students.find(s => s.tableNumber === tableNum);
    if (student) {
      setSelectedStudentId(student.id);
    } else {
      setSelectedTable(tableNum);
      setIsFormOpen(true);
    }
  };

  const handleSaveStudent = (newStudent: Student) => {
    const exists = students.some(s => s.id === newStudent.id);
    if (exists) {
      setStudents(prev => prev.map(s => s.id === newStudent.id ? newStudent : s));
    } else {
      setStudents(prev => [...prev, newStudent]);
    }
    setIsFormOpen(false);
    setSelectedTable(null);
  };

  const handleDeleteStudent = (id: string) => {
    if (window.confirm('Are you sure you want to remove this student? All history will be lost.')) {
      setStudents(prev => prev.filter(s => s.id !== id));
      setSelectedStudentId(null);
      setIsFormOpen(false);
    }
  };

  const handlePayment = (studentId: string, payment: Omit<PaymentRecord, 'id'>) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        // Calculate next due date (add 1 month)
        const currentDue = new Date(s.nextDueDate);
        const nextDue = new Date(currentDue.setMonth(currentDue.getMonth() + 1)).toISOString();

        const newRecord: PaymentRecord = {
          ...payment,
          id: crypto.randomUUID()
        };

        return {
          ...s,
          lastPaidDate: new Date().toISOString(),
          nextDueDate: nextDue,
          paymentHistory: [...s.paymentHistory, newRecord]
        };
      }
      return s;
    }));
  };

  const selectedStudent = students.find(s => s.id === selectedStudentId);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar - Desktop */}
      <aside className="w-full md:w-64 bg-slate-900 text-slate-300 md:h-screen sticky top-0 z-40 flex flex-col">
        <div className="p-6 flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-900">
            <Library className="w-6 h-6" />
          </div>
          <div>
            <h1 className="text-white font-bold text-lg leading-tight">LibMaster</h1>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Admin Portal</p>
          </div>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          <button 
            onClick={() => setView('grid')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'grid' ? 'bg-blue-600 text-white shadow-md' : 'hover:bg-slate-800'}`}
          >
            <LayoutGrid className="w-5 h-5" />
            <span className="font-semibold">Table Grid</span>
          </button>
          <button 
            onClick={() => setView('list')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-md' : 'hover:bg-slate-800'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-semibold">Directory</span>
          </button>
          <button 
            onClick={() => setView('analytics')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'analytics' ? 'bg-blue-600 text-white shadow-md' : 'hover:bg-slate-800'}`}
          >
            <BarChart3 className="w-5 h-5" />
            <span className="font-semibold">Insights</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
           <div className="bg-slate-800/50 p-4 rounded-2xl">
              <p className="text-xs text-slate-500 font-bold uppercase mb-2">Monthly Target</p>
              <div className="flex justify-between text-sm mb-1">
                <span>Revenue</span>
                <span className="text-white font-bold">₹{stats.monthlyRevenue}</span>
              </div>
              <div className="w-full bg-slate-700 h-1.5 rounded-full overflow-hidden">
                <div className="bg-emerald-500 h-full w-[65%]" />
              </div>
           </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-h-screen">
        {/* Header */}
        <header className="sticky top-0 bg-white/80 backdrop-blur-md border-b z-30 p-4 md:px-8 flex flex-col sm:flex-row items-center justify-between gap-4">
          <div className="relative w-full sm:w-96 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-blue-500 transition-colors" />
            <input 
              type="text" 
              placeholder="Search student, mobile or table #" 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-2.5 bg-slate-100 border-transparent border focus:bg-white focus:border-blue-400 rounded-2xl outline-none transition-all text-sm font-medium"
            />
          </div>

          <div className="flex items-center gap-3 w-full sm:w-auto">
            <button className="p-2.5 bg-slate-100 rounded-xl text-slate-600 hover:bg-slate-200 transition-colors relative">
              <Bell className="w-5 h-5" />
              {stats.overdue > 0 && <span className="absolute top-2 right-2 w-2 h-2 bg-rose-500 rounded-full border-2 border-white"></span>}
            </button>
            <button 
              onClick={() => { setSelectedTable(null); setIsFormOpen(true); }}
              className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-slate-800 transition-all shadow-lg shadow-slate-200"
            >
              <Plus className="w-5 h-5" /> Add Student
            </button>
          </div>
        </header>

        {/* Dynamic View Area */}
        <div className="flex-1 p-4 md:p-8">
          {/* Stats Bar */}
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-5">
              <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600">
                <Users className="w-6 h-6" />
              </div>
              <div>
                <p className="text-slate-500 text-sm font-medium">Occupancy</p>
                <p className="text-2xl font-black text-slate-800">{stats.total} / 40</p>
              </div>
            </div>
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-5">
              <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center text-rose-600">
                <Wallet className="w-6 h-6" />
              </div>
              <div>
                <p className="text-slate-500 text-sm font-medium">Overdue Accounts</p>
                <p className="text-2xl font-black text-slate-800">{stats.overdue}</p>
              </div>
            </div>
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-5">
              <div className="w-12 h-12 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-600">
                <IndianRupee className="w-6 h-6" />
              </div>
              <div>
                <p className="text-slate-500 text-sm font-medium">Est. Monthly Collection</p>
                <p className="text-2xl font-black text-slate-800">₹{stats.monthlyRevenue}</p>
              </div>
            </div>
          </div>

          {view === 'grid' && (
            <div className="bg-white rounded-3xl p-4 md:p-8 shadow-sm border border-slate-100 overflow-hidden">
               <div className="flex items-center justify-between mb-8">
                  <h2 className="text-xl font-bold text-slate-800">Visual Lab Layout</h2>
                  <div className="flex gap-4 text-xs font-bold uppercase tracking-widest">
                    <div className="flex items-center gap-1.5"><span className="w-3 h-3 rounded-full bg-emerald-500"></span> Paid</div>
                    <div className="flex items-center gap-1.5"><span className="w-3 h-3 rounded-full bg-rose-500"></span> Overdue</div>
                    <div className="flex items-center gap-1.5"><span className="w-3 h-3 rounded-full bg-slate-200"></span> Vacant</div>
                  </div>
               </div>
               <TableGrid students={students} onTableClick={handleTableClick} />
            </div>
          )}

          {view === 'list' && (
            <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-widest border-b">
                      <th className="px-6 py-4">Student</th>
                      <th className="px-6 py-4 text-center">Table</th>
                      <th className="px-6 py-4">Status</th>
                      <th className="px-6 py-4">Next Due</th>
                      <th className="px-6 py-4">Monthly Fee</th>
                      <th className="px-6 py-4 text-right">Action</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredStudents.length === 0 ? (
                      <tr>
                        <td colSpan={6} className="px-6 py-12 text-center text-slate-400 italic">No students found matching your search.</td>
                      </tr>
                    ) : (
                      filteredStudents.map(s => {
                        const isOverdue = new Date(s.nextDueDate) < new Date();
                        return (
                          <tr key={s.id} className="hover:bg-slate-50 transition-colors group">
                            <td className="px-6 py-4">
                              <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-xl bg-slate-100 flex items-center justify-center font-bold text-slate-500 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">
                                  {s.name.charAt(0)}
                                </div>
                                <div>
                                  <p className="font-bold text-slate-800 leading-none mb-1">{s.name}</p>
                                  <p className="text-xs text-slate-400 font-medium">{s.mobile}</p>
                                </div>
                              </div>
                            </td>
                            <td className="px-6 py-4 text-center">
                              <span className="px-3 py-1 bg-slate-100 text-slate-700 rounded-lg text-xs font-bold">#{s.tableNumber}</span>
                            </td>
                            <td className="px-6 py-4">
                              <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${isOverdue ? 'bg-rose-50 text-rose-600' : 'bg-emerald-50 text-emerald-600'}`}>
                                {isOverdue ? 'Overdue' : 'Paid'}
                              </span>
                            </td>
                            <td className="px-6 py-4">
                              <p className="text-sm font-semibold text-slate-600">{new Date(s.nextDueDate).toLocaleDateString()}</p>
                            </td>
                            <td className="px-6 py-4">
                              <p className="text-sm font-bold text-slate-800">₹{s.monthlyFee}</p>
                            </td>
                            <td className="px-6 py-4 text-right">
                              <button 
                                onClick={() => setSelectedStudentId(s.id)}
                                className="text-blue-600 font-bold text-sm hover:underline"
                              >
                                View Details
                              </button>
                            </td>
                          </tr>
                        );
                      })
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {view === 'analytics' && (
            <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
              <h2 className="text-xl font-bold text-slate-800 mb-8">Business Analytics</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="p-8 border-2 border-dashed border-slate-200 rounded-3xl text-center space-y-4">
                  <BarChart3 className="w-12 h-12 text-slate-300 mx-auto" />
                  <div>
                    <h3 className="font-bold text-slate-800">Revenue Trends</h3>
                    <p className="text-sm text-slate-400">Detailed charts and trend projections coming in next update.</p>
                  </div>
                </div>
                <div className="space-y-4">
                  <h3 className="font-bold text-slate-700">Recent Collections</h3>
                  {students.flatMap(s => s.paymentHistory).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 5).map(p => (
                    <div key={p.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                      <div>
                        <p className="text-sm font-bold text-slate-800">₹{p.amount}</p>
                        <p className="text-xs text-slate-500">{p.mode} • {new Date(p.date).toLocaleDateString()}</p>
                      </div>
                      <div className="text-right">
                         <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400">For</span>
                         <p className="text-xs font-bold text-slate-600">{p.forMonth}</p>
                      </div>
                    </div>
                  ))}
                  {students.every(s => s.paymentHistory.length === 0) && (
                    <p className="text-sm text-slate-400 italic">No recent transactions recorded.</p>
                  )}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Modals */}
      {isFormOpen && (
        <StudentForm 
          tableNumber={selectedTable || undefined}
