          student={selectedStudent}
          onClose={() => setSelectedStudentId(null)}
          onEdit={() => {
            setIsFormOpen(true);
            setSelectedStudentId(null);
            // Re-selecting will be handled by the StudentForm useEffect logic
            // but we need to pass the student specifically:
            setTimeout(() => {
              setStudents(prev => [...prev]); // trigger re-render if needed
            }, 0);
          }}
          onPayment={(p) => handlePayment(selectedStudent.id, p)}
        />
      )}

