                      ></div>
                      <div 
                        className="bg-blue-500 h-full transition-all duration-1000" 
                        style={{ width: `${(stats.totalOnline / (stats.totalCash + stats.totalOnline || 1)) * 100}%` }}
                      ></div>
                    </div>
                  </div>
                </div>

                <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
                  <div className="flex items-center justify-between mb-8">
                    <h2 className="text-xl font-bold text-slate-800">Recent Collections</h2>
                    <div className="p-2 bg-slate-50 text-slate-400 rounded-xl">
                      <ArrowUpRight className="w-5 h-5" />
                    </div>
                  </div>
                  <div className="space-y-4">
                    {students.flatMap(s => s.paymentHistory).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 4).map(p => (
                      <div key={p.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <div>
                          <p className="text-sm font-bold text-slate-800">₹{p.amount}</p>
                          <p className="text-xs text-slate-500">{p.mode} • {new Date(p.date).toLocaleDateString()}</p>
                        </div>
                        <div className="text-right">
                           <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400">For</span>
                           <p className="text-xs font-bold text-slate-600">{p.forMonth}</p>
                        </div>
                      </div>
                    ))}
                    {students.every(s => s.paymentHistory.length === 0) && (
                      <p className="text-sm text-slate-400 italic text-center py-4">No recent transactions recorded.</p>
                    )}
                  </div>
                </div>
              </div>

              {/* Bottom Row: Student-wise Cash vs Online Graph */}
              <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
                  <div>
                    <h2 className="text-xl font-bold text-slate-800">Payment Mode per Student</h2>
                    <p className="text-sm text-slate-500">Historical split of fees collected from each enrolled table</p>
