                  <div className="flex gap-4 text-xs font-bold uppercase tracking-widest text-slate-400">
                    <div className="flex items-center gap-1.5"><span className="w-3 h-3 rounded-full bg-emerald-500"></span> Cash</div>
                    <div className="flex items-center gap-1.5"><span className="w-3 h-3 rounded-full bg-blue-500"></span> Online</div>
