            setIsFormOpen(true);
            setSelectedStudentId(null);
          }}
          onPayment={(p) => handlePayment(selectedStudent.id, p)}
        />
      )}

      {/* Edge-case form trigger for EDITING */}
      {!isFormOpen && selectedStudent === null && selectedStudentId && (
        <StudentForm 
          student={students.find(s => s.id === selectedStudentId)}
          existingStudents={students}
          onSave={handleSaveStudent}
          onDelete={handleDeleteStudent}
          onClose={() => setSelectedStudentId(null)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Student, PaymentRecord, ViewState } from './types';
import { getStudents, saveStudents } from './services/storage';
import TableGrid from './components/TableGrid';
import StudentForm from './components/StudentForm';
import StudentDetails from './components/StudentDetails';
import { 
  Users, 
  LayoutGrid, 
  BarChart3, 
  Search, 
  Plus, 
  Library,
  Settings,
  Bell,
  Wallet,
  IndianRupee,
  PieChart,
  ArrowUpRight,
  Code,
  Heart,
  Cpu
} from 'lucide-react';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [view, setView] = useState<ViewState>('grid');
  const [selectedTable, setSelectedTable] = useState<number | null>(null);
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Initial load
  useEffect(() => {
    setStudents(getStudents());
  }, []);

  // Save on change
  useEffect(() => {
    saveStudents(students);
  }, [students]);

  const stats = useMemo(() => {
    const total = students.length;
    const overdue = students.filter(s => new Date(s.nextDueDate) < new Date()).length;
    const monthlyRevenue = students.reduce((acc, curr) => acc + curr.monthlyFee, 0);

    // Aggregate payment distribution
    const allPayments = students.flatMap(s => s.paymentHistory);
    const totalCash = allPayments.filter(p => p.mode === 'Cash').reduce((sum, p) => sum + p.amount, 0);
    const totalOnline = allPayments.filter(p => p.mode === 'Online').reduce((sum, p) => sum + p.amount, 0);

    // Calculate per-student distribution
    const studentCollections = students.map(s => {
      const cash = s.paymentHistory.filter(p => p.mode === 'Cash').reduce((sum, p) => sum + p.amount, 0);
      const online = s.paymentHistory.filter(p => p.mode === 'Online').reduce((sum, p) => sum + p.amount, 0);
      return {
        id: s.id,
        name: s.name,
        table: s.tableNumber,
        cash,
        online,
        total: cash + online
      };
    }).sort((a, b) => b.total - a.total);

    return { total, overdue, monthlyRevenue, totalCash, totalOnline, studentCollections };
  }, [students]);

  const filteredStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      s.mobile.includes(searchTerm) ||
      s.tableNumber.toString() === searchTerm
    );
  }, [students, searchTerm]);

  const handleTableClick = (tableNum: number) => {
    const student = students.find(s => s.tableNumber === tableNum);
    if (student) {
      setSelectedStudentId(student.id);
    } else {
      setSelectedTable(tableNum);
      setIsFormOpen(true);
    }
  };

  const handleSaveStudent = (newStudent: Student) => {
    const exists = students.some(s => s.id === newStudent.id);
    if (exists) {
      setStudents(prev => prev.map(s => s.id === newStudent.id ? newStudent : s));
    } else {
      setStudents(prev => [...prev, newStudent]);
    }
    setIsFormOpen(false);
    setSelectedTable(null);
  };

  const handleDeleteStudent = (id: string) => {
    if (window.confirm('Are you sure you want to remove this student? All history will be lost.')) {
      setStudents(prev => prev.filter(s => s.id !== id));
      setSelectedStudentId(null);
      setIsFormOpen(false);
    }
  };

  const handlePayment = (studentId: string, payment: Omit<PaymentRecord, 'id'>) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        // Calculate next due date (add 1 month)
        const currentDue = new Date(s.nextDueDate);
        const nextDue = new Date(currentDue.setMonth(currentDue.getMonth() + 1)).toISOString();

        const newRecord: PaymentRecord = {
          ...payment,
          id: crypto.randomUUID()
        };

        return {
          ...s,
          lastPaidDate: new Date().toISOString(),
          nextDueDate: nextDue,
          paymentHistory: [...s.paymentHistory, newRecord]
        };
      }
      return s;
    }));
  };

  const selectedStudent = students.find(s => s.id === selectedStudentId);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar - Desktop */}
      <aside className="w-full md:w-64 bg-slate-900 text-slate-300 md:h-screen sticky top-0 z-40 flex flex-col">
        <div className="p-6 flex items-center gap-3 text-white">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-900/40">
            <Library className="w-6 h-6" />
          </div>
          <div>
            <h1 className="font-bold text-lg leading-tight tracking-tight">LibMaster</h1>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Lab Manager</p>
          </div>
        </div>

        <nav className="flex-1 px-4 py-4 space-y-1">
          <button 
            onClick={() => setView('grid')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'grid' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'hover:bg-slate-800'}`}
          >
            <LayoutGrid className="w-5 h-5" />
            <span className="font-semibold text-sm">Table Grid</span>
          </button>
          <button 
            onClick={() => setView('list')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'hover:bg-slate-800'}`}
          >
            <Users className="w-5 h-5" />
            <span className="font-semibold text-sm">Directory</span>
          </button>
          <button 
            onClick={() => setView('analytics')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'analytics' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'hover:bg-slate-800'}`}
          >
            <BarChart3 className="w-5 h-5" />
            <span className="font-semibold text-sm">Insights</span>
          </button>
        </nav>

        <div className="px-4 py-4 space-y-4">
           {/* Revenue Indicator */}
           <div className="bg-slate-800/40 p-4 rounded-2xl border border-slate-800/50">
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mb-2">Monthly Target</p>
              <div className="flex justify-between items-end mb-1">
                <span className="text-xs text-slate-400">Total Projection</span>
