import React, { useState, useEffect, useMemo } from 'react';
import { Student, PaymentRecord, ViewState } from './types';
import { getStudents, saveStudents } from './services/storage';
import TableGrid from './components/TableGrid';
import StudentForm from './components/StudentForm';
import StudentDetails from './components/StudentDetails';
import { 
  Users, 
  LayoutGrid, 
  BarChart3, 
  Search, 
  Plus, 
  Library,
  Bell,
  Wallet,
  IndianRupee,
  PieChart,
  ArrowUpRight,
  Code,
  Heart,
  Trash2,
  Eye,
  MessageCircle
} from 'lucide-react';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [view, setView] = useState<ViewState>('grid');
  const [selectedTable, setSelectedTable] = useState<number | null>(null);
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    setStudents(getStudents());
  }, []);

  useEffect(() => {
    saveStudents(students);
  }, [students]);

  const stats = useMemo(() => {
    const total = students.length;
    const overdue = students.filter(s => new Date(s.nextDueDate) < new Date()).length;
    const monthlyRevenue = students.reduce((acc, curr) => acc + curr.monthlyFee, 0);

    const allPayments = students.flatMap(s => s.paymentHistory);
    const totalCash = allPayments.filter(p => p.mode === 'Cash').reduce((sum, p) => sum + p.amount, 0);
    const totalOnline = allPayments.filter(p => p.mode === 'Online').reduce((sum, p) => sum + p.amount, 0);

    const studentCollections = students.map(s => {
      const cash = s.paymentHistory.filter(p => p.mode === 'Cash').reduce((sum, p) => sum + p.amount, 0);
      const online = s.paymentHistory.filter(p => p.mode === 'Online').reduce((sum, p) => sum + p.amount, 0);
      return {
        id: s.id,
        name: s.name,
        table: s.tableNumber,
        cash,
        online,
        total: cash + online
      };
    }).sort((a, b) => b.total - a.total);

    return { total, overdue, monthlyRevenue, totalCash, totalOnline, studentCollections };
  }, [students]);

  const filteredStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      s.mobile.includes(searchTerm) ||
      s.tableNumber.toString() === searchTerm
    );
  }, [students, searchTerm]);

  const handleTableClick = (tableNum: number) => {
    const student = students.find(s => s.tableNumber === tableNum);
    if (student) {
      setSelectedStudentId(student.id);
    } else {
      setSelectedTable(tableNum);
      setIsFormOpen(true);
    }
  };

  const handleSaveStudent = (newStudent: Student) => {
    const exists = students.some(s => s.id === newStudent.id);
    if (exists) {
      setStudents(prev => prev.map(s => s.id === newStudent.id ? newStudent : s));
    } else {
      setStudents(prev => [...prev, newStudent]);
    }
    setIsFormOpen(false);
    setSelectedTable(null);
  };

  const handleDeleteStudent = (id: string) => {
    if (window.confirm('Are you sure you want to remove this student? All history will be lost.')) {
      setStudents(prev => prev.filter(s => s.id !== id));
      setSelectedStudentId(null);
      setIsFormOpen(false);
    }
  };

  const sendWhatsAppReminder = (student: Student) => {
    const message = `Hi ${student.name}, reminder from LibMaster: your fee of ₹${student.monthlyFee} for Table #${student.tableNumber} was due on ${new Date(student.nextDueDate).toLocaleDateString()}. Please clear the dues soon. Thank you!`;
    const encodedMessage = encodeURIComponent(message);
    const whatsappUrl = `https://wa.me/91${student.mobile.replace(/\D/g, '')}?text=${encodedMessage}`;
    window.open(whatsappUrl, '_blank');
  };

  const handlePayment = (studentId: string, payment: Omit<PaymentRecord, 'id'>) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        const currentDue = new Date(s.nextDueDate);
        const nextDue = new Date(currentDue.setMonth(currentDue.getMonth() + 1)).toISOString();

        const newRecord: PaymentRecord = {
          ...payment,
          id: crypto.randomUUID()
        };

        return {
          ...s,
          lastPaidDate: new Date().toISOString(),
          nextDueDate: nextDue,
          paymentHistory: [...s.paymentHistory, newRecord]
        };
      }
      return s;
    }));
  };

  const selectedStudent = students.find(s => s.id === selectedStudentId);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-white border-b sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 md:px-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between py-4 gap-4">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
                <Library className="w-6 h-6" />
              </div>
              <div>
                <h1 className="text-slate-900 font-bold text-xl leading-tight">LibMaster</h1>
                <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Lab Administration</p>
              </div>
            </div>

            <div className="relative flex-1 max-w-xl group">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-blue-500 transition-colors" />
              <input 
                type="text" 
                placeholder="Search students, mobile or table..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-12 pr-4 py-2.5 bg-slate-50 border border-slate-200 focus:bg-white focus:border-blue-400 rounded-2xl outline-none transition-all text-sm font-medium"
              />
            </div>

            <div className="flex items-center gap-3">
              <button className="p-2.5 bg-slate-50 rounded-xl text-slate-600 hover:bg-slate-100 transition-colors relative border border-slate-200">
                <Bell className="w-5 h-5" />
                {stats.overdue > 0 && <span className="absolute top-2 right-2 w-2 h-2 bg-rose-500 rounded-full border-2 border-white"></span>}
              </button>
              <button 
                onClick={() => { setSelectedTable(null); setIsFormOpen(true); }}
                className="flex items-center justify-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-slate-800 transition-all shadow-lg shadow-slate-200"
              >
                <Plus className="w-5 h-5" /> Add Student
              </button>
            </div>
          </div>

          <nav className="flex items-center gap-1 sm:gap-4 overflow-x-auto no-scrollbar pt-2 pb-0">
            {[
              { id: 'grid', label: 'Table Grid', icon: LayoutGrid },
              { id: 'list', label: 'Directory', icon: Users },
              { id: 'analytics', label: 'Insights', icon: BarChart3 }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setView(tab.id as ViewState)}
                className={`flex items-center gap-2 px-6 py-3 border-b-2 font-bold text-sm transition-all whitespace-nowrap
                  ${view === tab.id 
                    ? 'border-blue-600 text-blue-600 bg-blue-50/50 rounded-t-xl' 
                    : 'border-transparent text-slate-500 hover:text-slate-700 hover:bg-slate-50 rounded-t-xl'}`}
              >
                <tab.icon className="w-4 h-4" />
                {tab.label}
              </button>
            ))}
          </nav>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-8">
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 mb-8">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200 flex items-center gap-5">
            <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600">
              <Users className="w-6 h-6" />
            </div>
            <div>
              <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Occupancy</p>
              <p className="text-2xl font-black text-slate-800">{stats.total} / 40</p>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200 flex items-center gap-5">
            <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center text-rose-600">
              <Wallet className="w-6 h-6" />
            </div>
            <div>
              <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Overdue</p>
              <p className="text-2xl font-black text-slate-800">{stats.overdue}</p>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200 flex items-center gap-5">
            <div className="w-12 h-12 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-600">
              <IndianRupee className="w-6 h-6" />
            </div>
            <div>
              <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Monthly Revenue</p>
              <p className="text-2xl font-black text-slate-800">₹{stats.monthlyRevenue}</p>
            </div>
          </div>
        </div>

        <div className="min-h-[500px]">
          {view === 'grid' && (
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-200">
               <div className="flex items-center justify-between mb-8">
                  <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                    <LayoutGrid className="w-5 h-5 text-blue-500" /> Lab Layout
                  </h2>
                  <div className="flex gap-4 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                    <div className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-emerald-500"></span> Paid</div>
                    <div className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-rose-500"></span> Overdue</div>
                    <div className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-slate-200"></span> Vacant</div>
                  </div>
               </div>
               <TableGrid students={students} onTableClick={handleTableClick} />
            </div>
          )}

          {view === 'list' && (
            <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
                      <th className="px-6 py-4">Student Name</th>
                      <th className="px-6 py-4 text-center">Table</th>
                      <th className="px-6 py-4">Status</th>
                      <th className="px-6 py-4">Next Payment</th>
                      <th className="px-6 py-4">Monthly Fee</th>
                      <th className="px-6 py-4 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredStudents.length === 0 ? (
                      <tr>
                        <td colSpan={6} className="px-6 py-20 text-center text-slate-400 italic">No student records match your current search criteria.</td>
                      </tr>
                    ) : (
                      filteredStudents.map(s => {
                        const isOverdue = new Date(s.nextDueDate) < new Date();
                        return (
                          <tr key={s.id} className="hover:bg-slate-50 transition-colors group">
                            <td className="px-6 py-4">
                              <div className="flex items-center gap-3">
                                <div className="w-9 h-9 rounded-xl bg-slate-100 flex items-center justify-center font-bold text-slate-500 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">
                                  {s.name.charAt(0)}
                                </div>
                                <div>
                                  <p className="font-bold text-slate-800 text-sm leading-none mb-1">{s.name}</p>
                                  <p className="text-[11px] text-slate-400 font-medium">{s.mobile}</p>
                                </div>
                              </div>
                            </td>
                            <td className="px-6 py-4 text-center">
                              <span className="px-3 py-1 bg-slate-100 text-slate-700 rounded-lg text-xs font-bold">#{s.tableNumber}</span>
                            </td>
                            <td className="px-6 py-4">
                              <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${isOverdue ? 'bg-rose-50 text-rose-600 border border-rose-100' : 'bg-emerald-50 text-emerald-600 border border-emerald-100'}`}>
                                {isOverdue ? 'Overdue' : 'Active'}
                              </span>
                            </td>
                            <td className="px-6 py-4">
                              <p className="text-sm font-semibold text-slate-600">{new Date(s.nextDueDate).toLocaleDateString()}</p>
                            </td>
                            <td className="px-6 py-4 font-bold text-slate-800 text-sm">₹{s.monthlyFee}</td>
                            <td className="px-6 py-4 text-right">
                              <div className="flex items-center justify-end gap-2">
                                {isOverdue && (
                                  <button 
                                    onClick={() => sendWhatsAppReminder(s)}
                                    className="p-2 text-[#25D366] hover:bg-emerald-50 rounded-lg transition-colors"
                                    title="Send WhatsApp Reminder"
                                  >
                                    <MessageCircle className="w-4 h-4" />
                                  </button>
                                )}
                                <button 
                                  onClick={() => setSelectedStudentId(s.id)}
                                  className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                  title="View Details"
                                >
                                  <Eye className="w-4 h-4" />
                                </button>
                                <button 
                                  onClick={() => handleDeleteStudent(s.id)}
                                  className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors"
                                  title="Delete Student"
                                >
                                  <Trash2 className="w-4 h-4" />
                                </button>
                              </div>
                            </td>
                          </tr>
                        );
                      })
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {view === 'analytics' && (
            <div className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-200">
                  <div className="flex items-center justify-between mb-8">
                    <h2 className="text-lg font-bold text-slate-800">Total Revenue Distribution</h2>
                    <div className="p-2 bg-blue-50 text-blue-600 rounded-xl">
                      <PieChart className="w-5 h-5" />
                    </div>
                  </div>
                  <div className="space-y-6">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-3 text-slate-600 font-medium text-sm">
                        <div className="w-3 h-3 rounded-full bg-emerald-500"></div> Cash
                      </div>
                      <span className="font-bold text-slate-800">₹{stats.totalCash}</span>
                    </div>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-3 text-slate-600 font-medium text-sm">
                        <div className="w-3 h-3 rounded-full bg-blue-500"></div> Online
                      </div>
                      <span className="font-bold text-slate-800">₹{stats.totalOnline}</span>
                    </div>
                    <div className="relative h-4 w-full bg-slate-100 rounded-full overflow-hidden flex shadow-inner">
                      <div 
                        className="bg-emerald-500 h-full transition-all duration-1000" 
                        style={{ width: `${(stats.totalCash / (stats.totalCash + stats.totalOnline || 1)) * 100}%` }}
                      ></div>
                      <div 
                        className="bg-blue-500 h-full transition-all duration-1000" 
                        style={{ width: `${(stats.totalOnline / (stats.totalCash + stats.totalOnline || 1)) * 100}%` }}
                      ></div>
                    </div>
                  </div>
                </div>

                <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-200">
                  <div className="flex items-center justify-between mb-8">
                    <h2 className="text-lg font-bold text-slate-800">Recent Collections</h2>
                    <div className="p-2 bg-slate-50 text-slate-400 rounded-xl">
                      <ArrowUpRight className="w-5 h-5" />
                    </div>
                  </div>
                  <div className="space-y-3">
                    {students.flatMap(s => s.paymentHistory).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 4).map(p => (
                      <div key={p.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <div>
                          <p className="text-sm font-bold text-slate-800">₹{p.amount}</p>
                          <p className="text-[10px] text-slate-500 uppercase tracking-wide">{p.mode} • {new Date(p.date).toLocaleDateString()}</p>
                        </div>
                        <div className="text-right">
                           <p className="text-[10px] font-bold text-slate-400 uppercase">Period</p>
                           <p className="text-xs font-bold text-slate-700">{p.forMonth}</p>
                        </div>
                      </div>
                    ))}
                    {students.every(s => s.paymentHistory.length === 0) && (
                      <p className="text-sm text-slate-400 italic text-center py-10">Waiting for first payment record...</p>
                    )}
                  </div>
                </div>
              </div>

              <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-200">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
                  <div>
                    <h2 className="text-lg font-bold text-slate-800">Student Revenue Breakdown</h2>
                    <p className="text-xs text-slate-500 mt-1">Split between Online and Cash payments per student</p>
                  </div>
                  <div className="flex gap-4 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                    <div className="flex items-center gap-1.5"><span className="w-3 h-3 rounded-full bg-emerald-400"></span> Cash</div>
                    <div className="flex items-center gap-1.5"><span className="w-3 h-3 rounded-full bg-blue-400"></span> Online</div>
                  </div>
                </div>

                <div className="space-y-6 max-h-[600px] overflow-y-auto pr-4 custom-scrollbar">
                  {stats.studentCollections.length === 0 ? (
                    <div className="py-20 text-center text-slate-300">
                      <BarChart3 className="w-12 h-12 mx-auto mb-4 opacity-20" />
                      <p className="text-sm font-medium tracking-wide">No data to display yet.</p>
                    </div>
                  ) : (
                    stats.studentCollections.map((sc) => (
                      <div key={sc.id} className="group">
                        <div className="flex items-center justify-between mb-2">
                          <div className="flex items-center gap-2">
                            <span className="bg-slate-100 text-slate-500 text-[10px] font-black px-1.5 py-0.5 rounded border border-slate-200">T{sc.table}</span>
                            <span className="text-sm font-bold text-slate-700 group-hover:text-blue-600 transition-colors">{sc.name}</span>
                          </div>
                          <span className="text-sm font-black text-slate-900 tracking-tight">₹{sc.total}</span>
                        </div>
                        <div className="relative h-5 w-full bg-slate-50 rounded-lg overflow-hidden flex border border-slate-100">
                          {sc.total > 0 ? (
                            <>
                              <div 
                                className="bg-emerald-400 h-full transition-all duration-700 hover:brightness-105" 
                                style={{ width: `${(sc.cash / sc.total) * 100}%` }}
                                title={`Cash: ₹${sc.cash}`}
                              ></div>
                              <div 
                                className="bg-blue-400 h-full transition-all duration-700 hover:brightness-105" 
                                style={{ width: `${(sc.online / sc.total) * 100}%` }}
                                title={`Online: ₹${sc.online}`}
                              ></div>
                            </>
                          ) : (
                            <div className="w-full h-full flex items-center px-4 text-[10px] text-slate-300 italic font-medium">New Student - Pending Payments</div>
                          )}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="mt-16 border-t border-slate-200 bg-white">
        <div className="max-w-7xl mx-auto px-8 py-16 text-center flex flex-col items-center">
          <div className="mb-6 p-4 bg-blue-50 rounded-3xl text-blue-600 inline-block shadow-sm">
            <Code className="w-8 h-8" />
          </div>

          <div className="space-y-4 max-w-2xl mx-auto">
            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.5em] mb-4">Precision Engineering & Design</p>
            <h2 className="text-4xl md:text-5xl lg:text-6xl font-black text-slate-900 tracking-tighter mb-4">
              Developed by <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-indigo-600">Atharva N. Deshmukh</span>
            </h2>
            <p className="text-slate-500 text-lg md:text-xl font-medium leading-relaxed">
              Specialized in crafting premium administrative interfaces with cutting-edge technology and minimalist aesthetics.
            </p>
          </div>

          <div className="mt-12 flex flex-col md:flex-row items-center gap-6 md:gap-12">
            <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-widest">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> High Performance
            </div>
            <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-widest">
              <span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span> Responsive Design
            </div>
            <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-widest">
              <span className="w-1.5 h-1.5 rounded-full bg-indigo-500"></span> Secure Data
            </div>
          </div>

          <div className="mt-12 flex items-center gap-2 text-slate-400 font-bold text-xs uppercase tracking-widest opacity-60">
             Build v2.1.0 • Made with <Heart className="w-3.5 h-3.5 text-rose-500 fill-current inline" /> in 2025
          </div>
        </div>
      </footer>

      {isFormOpen && (
        <StudentForm 
          tableNumber={selectedTable || undefined}
          existingStudents={students}
          onSave={handleSaveStudent}
          onClose={() => { setIsFormOpen(false); setSelectedTable(null); }}
        />
      )}

      {selectedStudent && (
        <StudentDetails 
          student={selectedStudent}
          onClose={() => setSelectedStudentId(null)}
          onEdit={() => {
            setIsFormOpen(true);
            setSelectedStudentId(null);
          }}
          onPayment={(p) => handlePayment(selectedStudent.id, p)}
          onDelete={handleDeleteStudent}
        />
      )}

      {!isFormOpen && selectedStudent === null && selectedStudentId && (
        <StudentForm 
          student={students.find(s => s.id === selectedStudentId)}
          existingStudents={students}
          onSave={handleSaveStudent}
          onDelete={handleDeleteStudent}
          onClose={() => setSelectedStudentId(null)}
        />
      )}
    </div>
  );
};

export default App;
